args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT (COUNT(DISTINCT ?player) AS ?count)
WHERE {
  ?player wdt:P31 wd:Q5 .
  ?player p:P54 ?membership .
  ?membership ps:P54 wd:Q457163 ;
              pq:P580 ?startTime .
  OPTIONAL { ?membership pq:P582 ?endTime }
  FILTER (?startTime <= "2021-12-01T00:00:00Z"^^xsd:dateTime)
  FILTER (!BOUND(?endTime) || ?endTime >= "2021-12-01T00:00:00Z"^^xsd:dateTime)
}
